746	func (s *Store) SetExecutionCooldown(id string, until time.Time, status, detail string) error {
747		return s.Update(id, func(b *Bead) {
748			if b.Extra == nil {
749				b.Extra = make(map[string]any)
750			}
751			b.Extra["execute-loop-retry-after"] = until.UTC().Format(time.RFC3339)
752			if status != "" {
753				b.Extra["execute-loop-last-status"] = status
754			}
755			if detail != "" {
756				b.Extra["execute-loop-last-detail"] = detail
757			}
758		})
759	}
