761	// IncrNoChangesCount increments the execute-loop no-changes counter for a bead
762	// and returns the new count. Used by the execute-bead worker to detect when a
763	// bead should be auto-closed after repeated no-change attempts.
764	func (s *Store) IncrNoChangesCount(id string) (int, error) {
765		var newCount int
766		err := s.Update(id, func(b *Bead) {
767			if b.Extra == nil {
768				b.Extra = make(map[string]any)
769			}
770			var count int
771			if v, ok := b.Extra["execute-loop-no-changes-count"]; ok {
772				switch n := v.(type) {
773				case int:
774					count = n
775				case float64:
776					count = int(n)
777				case int64:
778					count = int(n)
779				}
780			}
781			count++
782			b.Extra["execute-loop-no-changes-count"] = count
783			newCount = count
784		})
785		return newCount, err
786	}
787	
788	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
789	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
790	// DDx-authored beads always round-trip through `bd import`. Empirically
791	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
792	const MaxFieldBytes = 65535
793	
794	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
795	// need to preserve the full payload should persist it to a sidecar artifact
796	// and store a path reference in the field; this function is the defense-in-
797	// depth cap for code paths that don't. Returns the input unchanged when it
798	// fits; otherwise returns head+tail truncation with a byte-count marker.
799	func capFieldBytes(s string) string {
800		if len(s) <= MaxFieldBytes {
801			return s
802		}
803		// Reserve a marker that always fits; keep head heavy (2/3) so
804		// human-readable context is preserved for the common short-rationale case.
805		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
806		budget := MaxFieldBytes - len(marker)
807		if budget <= 0 {
808			return s[:MaxFieldBytes]
809		}
810		head := (budget * 2) / 3
811		tail := budget - head
812		return s[:head] + marker + s[len(s)-tail:]
813	}
814	
815	// Cancel-marker keys on Bead.Extra. ADR-022 §Cancel SLA: an operator-initiated
816	// cancel writes cancel-requested:true; the worker that honors the cancel writes
817	// cancel-honored:true alongside it.
818	const (
819		ExtraCancelRequested = "cancel-requested"
820		ExtraCancelHonored   = "cancel-honored"
821	)
822	
823	// RequestCancel writes Extra[cancel-requested]=true on the bead. Idempotent:
824	// if cancel-honored is already set the call is a silent no-op (the prior cancel
825	// was already consumed). Returns true when the marker is now set on the bead
826	// (either by this call or a prior one).
827	func (s *Store) RequestCancel(id string) (bool, error) {
828		var set bool
829		err := s.Update(id, func(b *Bead) {
830			if b.Extra == nil {
831				b.Extra = make(map[string]any)
832			}
833			if isExtraTrue(b.Extra[ExtraCancelHonored]) {
834				set = isExtraTrue(b.Extra[ExtraCancelRequested])
835				return
836			}
837			b.Extra[ExtraCancelRequested] = true
838			set = true
839		})
840		return set, err
841	}
