880	func (s *Store) AppendEvent(id string, event BeadEvent) error {
881		if event.CreatedAt.IsZero() {
882			event.CreatedAt = time.Now().UTC()
883		}
884		// Defense in depth: cap every event body regardless of caller. The
885		// reviewer write path separately persists the full stream to an artifact
886		// and emits a <=512-byte body; this cap catches anything else.
887		event.Body = capFieldBytes(event.Body)
888		event.Summary = capFieldBytes(event.Summary)
889		// Two storage shapes are possible here: inline Extra["events"] for active
890		// beads, and a sidecar attachment for closed/archived beads (ADR-004
891		// attachment model). When the bead has been externalized we append to the
892		// sidecar and leave the row untouched aside from updated_at.
893		var appendedToAttachment bool
894		if err := s.Update(id, func(b *Bead) {
895			if b.Extra == nil {
896				b.Extra = make(map[string]any)
897			}
898			if hasEventsAttachment(b) {
899				appendedToAttachment = true
900				return
901			}
902			var events []BeadEvent
903			if raw, ok := b.Extra["events"]; ok {
904				events = decodeBeadEvents(raw)
905			}
906			events = append(events, event)
907			b.Extra["events"] = encodeEventsForExtra(events)
908		}); err != nil {
909			return err
910		}
911		if !appendedToAttachment {
912			return nil
913		}
914		// Append to the sidecar under the store lock so concurrent readers and
915		// writers see a consistent events log.
916		return s.WithLock(func() error {
917			existing, err := s.readEventsAttachment(id)
918			if err != nil {
919				return err
920			}
921			existing = append(existing, event)
922			return s.writeEventsAttachment(id, existing)
923		})
924	}
