926	// Events returns the bead's evidence history in insertion order. Reads are
927	// transparent across storage shapes: inline Extra["events"] for active beads,
928	// or the externalized sidecar referenced by Extra[events_attachment] once the
929	// bead has been closed.
930	func (s *Store) Events(id string) ([]BeadEvent, error) {
931		b, err := s.Get(id)
932		if err != nil {
933			return nil, err
934		}
935		events, err := s.eventsForBead(b)
936		if err != nil {
937			return nil, err
938		}
939		if len(events) == 0 {
940			return []BeadEvent{}, nil
941		}
942		out := make([]BeadEvent, len(events))
943		copy(out, events)
944		return out, nil
945	}
