962	func decodeBeadEvents(raw any) []BeadEvent {
963		switch v := raw.(type) {
964		case []BeadEvent:
965			out := make([]BeadEvent, len(v))
966			copy(out, v)
967			return out
968		case []any:
969			out := make([]BeadEvent, 0, len(v))
970			for _, item := range v {
971				m, ok := item.(map[string]any)
972				if !ok {
973					continue
974				}
975				out = append(out, beadEventFromMap(m))
976			}
977			return out
978		case []map[string]any:
979			out := make([]BeadEvent, 0, len(v))
980			for _, item := range v {
981				out = append(out, beadEventFromMap(item))
982			}
983			return out
984		default:
985			return nil
986		}
987	}
