989	func beadEventFromMap(m map[string]any) BeadEvent {
990		e := BeadEvent{}
991		if v, ok := m["kind"].(string); ok {
992			e.Kind = v
993		}
994		if v, ok := m["summary"].(string); ok {
995			e.Summary = v
996		}
997		if v, ok := m["body"].(string); ok {
998			e.Body = v
999		}
1000		if v, ok := m["actor"].(string); ok {
1001			e.Actor = v
1002		}
1003		if v, ok := m["source"].(string); ok {
1004			e.Source = v
1005		}
1006		if v, ok := m["created_at"].(string); ok {
1007			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
1008				e.CreatedAt = parsed
1009			}
1010		}
1011		return e
