1031	// externalizeEvents moves a bead's inline events into its sidecar attachment
1032	// under a fresh lock. Safe to call repeatedly — no-op when there are no
1033	// inline events (already externalized, or none recorded).
1034	func (s *Store) externalizeEvents(id string) error {
1035		return s.WithLock(func() error {
1036			beads, _, err := s.readAllLatestRaw()
1037			if err != nil {
1038				return err
1039			}
1040			for i := range beads {
1041				if beads[i].ID != id {
1042					continue
1043				}
1044				if err := s.externalizeEventsInPlace(&beads[i]); err != nil {
1045					return err
1046				}
1047				return s.WriteAll(beads)
1048			}
1049			return nil
1050		})
1051	}
