1053	// ErrClosureGateRejected indicates a close was refused because the bead does
1054	// not carry the evidence required for an automated closure: a terminal
1055	// verdict event (review APPROVE with non-empty rationale, or an explicit
1056	// review-skipped / manual-close marker) AND an execution-evidence marker
1057	// (closing_commit_sha, session_id, or an execute-bead success event in the
1058	// events history).
1059	//
1060	// Automated execute-loop paths (execute-bead + reviewer) always go through
1061	// CloseWithEvidence. The plain Store.Close remains as the manual
1062	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
1063	// acceptance §1).
1064	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
1065	
1066	// ClosureGate inspects a bead and returns nil iff the close is safe. It
1067	// rejects only the specific shapes that caused the 2026-04-18/20
1068	// review-malfunction incidents:
1069	//
1070	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
1071	//     closing_commit_sha. Rejected by the execution-evidence check —
1072	//     closing_commit_sha must be non-empty OR at least one event must exist.
1073	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
1074	//     body is empty. Rejected — APPROVE with no rationale is exactly the
1075	//     parse-mis-extract shape the reviewer bug produced.
1076	//
1077	// Beads without a review step (--no-review, no Reviewer configured, already-
1078	// satisfied paths) pass the gate as long as they carry execution evidence.
1079	// This keeps the surface small: the gate catches known-bad shapes, not every
1080	// conceivable edge case. Additional invariants belong in future dedicated
1081	// beads so the rejection reason stays auditable.
1082	func ClosureGate(b *Bead) error {
1083		if b == nil {
1084			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
1085		}
1086		hasClosingCommit := false
1087		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
1088			hasClosingCommit = true
1089		}
1090		events := decodeBeadEvents(b.Extra["events"])
1091		// Externalized events still count as evidence for the gate. We only need
1092		// to know whether *some* event history exists, not iterate it; the
1093		// gate's APPROVE-with-empty-rationale check below relies on inline events
1094		// (the verdict is recorded before externalization).
1095		hasAttachedEvents := hasEventsAttachment(b)
1096		// Reject the axon-c5cc071a shape: no events AND no closing commit.
1097		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
1098			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
1099		}
1100		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
1101		for _, e := range events {
1102			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
1103				if strings.TrimSpace(e.Body) == "" {
1104					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
1105				}
1106			}
1107		}
1108		return nil
1109	}
