1111	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
1112	// sessionID is the agent session that completed the work.
1113	// commitSHA is the exact closing commit SHA when it is known.
1114	//
1115	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
1116	// via this path without a terminal verdict event plus execution evidence.
1117	// Store.Close is the manual-administration escape hatch when the gate is
1118	// inappropriate.
1119	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
1120		if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
1121			return err
1122		}
1123		// Externalize events only when the gate actually transitioned the bead
1124		// to closed; rejected closes leave the bead open and inline.
1125		if b, err := s.Get(id); err == nil && b != nil && b.Status == StatusClosed {
1126			if err := s.externalizeEvents(id); err != nil {
1127				return err
1128			}
1129		}
1130		s.maybeOpportunisticArchive()
1131		return nil
1132	}
