1134	func (s *Store) closeWithEvidence(id string, sessionID string, commitSHA string) error {
1135		return s.Update(id, func(b *Bead) {
1136			if b.Extra == nil {
1137				b.Extra = make(map[string]any)
1138			}
1139			if sessionID != "" {
1140				b.Extra["session_id"] = sessionID
1141			}
1142			if commitSHA != "" {
1143				b.Extra["closing_commit_sha"] = commitSHA
1144			}
1145			if err := ClosureGate(b); err != nil {
1146				// Surface via bead notes so a later operator audit can see why the
1147				// close was refused; a single error path would be dropped by the
1148				// Update callback signature (no error return).
1149				appendClosureRejectNote(b, err)
1150				return
1151			}
1152			b.Status = StatusClosed
1153		})
1154	}
