1181	// Reopen sets a bead's status back to open, clears claim fields, optionally
1182	// appends notes, and records an immutable reopen event — all in one atomic
1183	// lock acquisition.
1184	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
1185		now := time.Now().UTC()
1186		return s.WithLock(func() error {
1187			beads, _, err := s.readAllLatestRaw()
1188			if err != nil {
1189				return err
1190			}
1191			found := false
1192			for i := range beads {
1193				if beads[i].ID != id {
1194					continue
1195				}
1196				b := &beads[i]
1197				b.Status = StatusOpen
1198				b.Owner = ""
1199				b.UpdatedAt = now
1200				if b.Extra == nil {
1201					b.Extra = make(map[string]any)
1202				}
1203				// Clear claim fields
1204				delete(b.Extra, "claimed-at")
1205				delete(b.Extra, "claimed-pid")
1206				delete(b.Extra, "claimed-machine")
1207				delete(b.Extra, "claimed-session")
1208				delete(b.Extra, "claimed-worktree")
1209				delete(b.Extra, "execute-loop-heartbeat-at")
1210				// Append notes
1211				if appendNotes != "" {
1212					if b.Notes != "" {
1213						b.Notes = b.Notes + "\n\n" + appendNotes
1214					} else {
1215						b.Notes = appendNotes
1216					}
1217				}
1218				// Record reopen event. If events were externalized at close,
1219				// pull them back inline so the active row carries the full
1220				// history again and the attachment ref is dropped.
1221				if hasEventsAttachment(b) {
1222					if err := s.inlineEventsInPlace(b); err != nil {
1223						return err
1224					}
1225					_ = os.Remove(s.eventsAttachmentPath(b.ID))
1226				}
1227				var events []BeadEvent
1228				if raw, ok := b.Extra["events"]; ok {
1229					events = decodeBeadEvents(raw)
1230				}
1231				evt := BeadEvent{
1232					Kind:      "reopen",
1233					CreatedAt: now,
1234				}
1235				if reason != "" {
1236					evt.Summary = reason
1237				}
1238				events = append(events, evt)
1239				encoded := make([]map[string]any, 0, len(events))
1240				for _, e := range events {
1241					encoded = append(encoded, map[string]any{
1242						"kind":       e.Kind,
1243						"summary":    e.Summary,
1244						"body":       e.Body,
1245						"actor":      e.Actor,
1246						"created_at": e.CreatedAt,
1247						"source":     e.Source,
1248					})
1249				}
1250				b.Extra["events"] = encoded
1251				if err := s.validateBead(b); err != nil {
1252					return err
1253				}
1254				if err := s.runHook("validate-bead-update", b); err != nil {
1255					return err
1256				}
1257				found = true
1258				break
1259			}
1260			if !found {
1261				return fmt.Errorf("bead: not found: %s", id)
1262			}
1263			return s.WriteAll(beads)
1264		})
1265	}
