1300	// matchesWhere returns true if the bead satisfies all key=value predicates.
1301	// It checks known struct fields first, then falls back to Extra.
1302	func matchesWhere(b Bead, where map[string]string) bool {
1303		for k, v := range where {
1304			var actual string
1305			switch k {
1306			case "id":
1307				actual = b.ID
1308			case "title":
1309				actual = b.Title
1310			case "status":
1311				actual = b.Status
1312			case "issue_type":
1313				actual = b.IssueType
1314			case "owner":
1315				actual = b.Owner
1316			case "assignee":
1317				actual = b.Owner
1318			case "parent":
1319				actual = b.Parent
1320			case "description":
1321				actual = b.Description
1322			case "acceptance":
1323				actual = b.Acceptance
1324			case "notes":
1325				actual = b.Notes
1326			default:
1327				// Fall back to Extra map for unknown/workflow-specific fields
1328				if b.Extra != nil {
1329					if ev, ok := b.Extra[k]; ok {
1330						actual = fmt.Sprintf("%v", ev)
1331					}
1332				}
1333			}
1334			if actual != v {
1335				return false
1336			}
1337		}
1338		return true
1339	}
