1353	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1354	// they are NOT execution-eligible: epic containers, retry cooldown,
1355	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1356	// emits when the execution queue is empty but `ddx bead ready` is not.
1357	type ReadyExecutionBreakdown struct {
1358		SkippedEpics       []string
1359		SkippedOnCooldown  []string
1360		SkippedNotEligible []string
1361		SkippedSuperseded  []string
1362		NextRetryAfter     string
1363	}
1364	
1365	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1366		out := ReadyExecutionBreakdown{}
1367		ready, err := s.Ready()
1368		if err != nil {
1369			return out, err
1370		}
1371		now := time.Now().UTC()
1372		var soonestRetry time.Time
1373		for _, b := range ready {
1374			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1375				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1376					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1377						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1378						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1379							soonestRetry = retryAfter
1380						}
1381						continue
1382					}
1383				}
1384			}
1385			if eligible, ok := b.Extra["execution-eligible"]; ok {
1386				if val, isBool := eligible.(bool); isBool && !val {
1387					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1388					continue
1389				}
1390			}
1391			if sup, ok := b.Extra["superseded-by"]; ok {
1392				if s, isStr := sup.(string); isStr && s != "" {
1393					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1394					continue
1395				}
1396			}
1397		}
1398		if !soonestRetry.IsZero() {
1399			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1400		}
1401		return out, nil
1402	}
1403	
1404	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1405		beads, err := s.ReadAll()
1406		if err != nil {
1407			return nil, err
1408		}
1409		statusMap := make(map[string]string)
1410		for _, b := range beads {
1411			statusMap[b.ID] = b.Status
1412		}
1413	
1414		var ready []Bead
1415		for _, b := range beads {
1416			if b.Status != StatusOpen {
1417				// Surface stalled in_progress beads so a fresh worker can
1418				// reclaim them atomically in Claim().
1419				if executionOnly && b.Status == StatusInProgress && heartbeatIsStale(b.Extra) {
1420					// fall through to dependency check below
1421				} else {
1422					continue
1423				}
1424			}
1425			allSatisfied := true
1426			for _, depID := range b.DepIDs() {
1427				if statusMap[depID] != StatusClosed {
1428					allSatisfied = false
1429					break
1430				}
1431			}
1432			if !allSatisfied {
1433				continue
1434			}
1435			if executionOnly {
1436				// Filter by execution-eligible (default true if absent)
1437				eligible, ok := b.Extra["execution-eligible"]
1438				if ok {
1439					if val, isBool := eligible.(bool); isBool && !val {
