1503		statusMap := make(map[string]string)
1504		for _, b := range beads {
1505			statusMap[b.ID] = b.Status
1506		}
1507	
1508		now := time.Now().UTC()
1509		var entries []BlockedBead
1510		for _, b := range beads {
1511			if b.Status != StatusOpen {
