1640	func (s *Store) DepAdd(id, depID string) error {
1641		return s.WithLock(func() error {
1642			beads, _, err := s.readAllLatestRaw()
1643			if err != nil {
1644				return err
1645			}
1646			var target *Bead
1647			depExists := false
1648			for i := range beads {
1649				if beads[i].ID == id {
1650					target = &beads[i]
1651				}
1652				if beads[i].ID == depID {
1653					depExists = true
1654				}
1655			}
1656			if target == nil {
