1692	// DepTree returns a text representation of the dependency tree.
1693	func (s *Store) DepTree(rootID string) (string, error) {
1694		beads, err := s.ReadAll()
1695		if err != nil {
1696			return "", err
1697		}
1698		// Pull in archive partner so the tree survives `bead migrate` — closed
1699		// beads stored only in the archive must still appear.
1700		if s.Collection == DefaultCollection {
1701			archive := s.archivePartner()
1702			if archived, aerr := archive.ReadAll(); aerr == nil {
1703				seen := make(map[string]bool, len(beads))
1704				for _, b := range beads {
1705					seen[b.ID] = true
1706				}
1707				for _, b := range archived {
1708					if seen[b.ID] {
1709						continue
1710					}
1711					beads = append(beads, b)
1712				}
1713			}
1714		}
1715		byID := make(map[string]*Bead)
1716		for i := range beads {
1717			byID[beads[i].ID] = &beads[i]
1718		}
1719	
1720		if rootID != "" {
1721			target, ok := byID[rootID]
1722			if !ok {
1723				return "", fmt.Errorf("bead: not found: %s", rootID)
1724			}
1725			var sb strings.Builder
1726			// Walk up: show the dependency chain (what this node depends on)
1727			depChain := s.depChainUp(byID, rootID)
1728			if len(depChain) > 0 {
1729				// Print deps as the tree root(s), with the target as their child
1730				for _, depID := range depChain {
1731					if dep, ok := byID[depID]; ok {
1732						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1733					}
1734				}
1735			}
1736			// Print the target node
1737			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1738			// Print dependents (what depends on this node)
1739			var children []string
1740			for _, other := range sortedKeys(byID) {
1741				if byID[other].HasDep(rootID) {
1742					children = append(children, other)
1743				}
1744			}
1745			for _, child := range children {
1746				s.printTree(&sb, byID, child, "  ", true)
1747			}
1748			return sb.String(), nil
1749		}
1750	
1751		// Find roots (beads that have no dependencies themselves)
1752		var roots []string
1753		for _, b := range beads {
1754			if len(b.Dependencies) == 0 {
1755				roots = append(roots, b.ID)
1756			}
1757		}
1758		sort.Strings(roots)
1759	
1760		var sb strings.Builder
1761		for i, root := range roots {
1762			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1763		}
1764		return sb.String(), nil
1765	}
