1767	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1768		b, ok := byID[id]
1769		if !ok {
1770			return
1771		}
1772	
1773		connector := "├── "
1774		if last {
1775			connector = "└── "
1776		}
1777		if prefix == "" {
1778			connector = ""
1779		}
1780	
1781		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1782	
1783		// Find beads that depend on this one (children in the tree)
1784		var children []string
1785		for _, other := range sortedKeys(byID) {
1786			if byID[other].HasDep(id) {
1787				children = append(children, other)
1788			}
1789		}
1790	
1791		childPrefix := prefix
1792		if prefix != "" {
1793			if last {
1794				childPrefix += "    "
1795			} else {
1796				childPrefix += "│   "
1797			}
1798		}
1799	
1800		for i, child := range children {
1801			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
1802		}
1803	}
