1815	func (s *Store) validateBead(b *Bead) error {
1816		if strings.TrimSpace(b.Title) == "" {
1817			return fmt.Errorf("bead: title is required")
1818		}
1819		if b.Priority < MinPriority || b.Priority > MaxPriority {
1820			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
1821		}
1822		switch b.Status {
1823		case StatusOpen, StatusInProgress, StatusClosed, StatusBlocked,
1824			StatusProposed, StatusCancelled:
1825			// ok
1826		default:
1827			return fmt.Errorf("bead: invalid status: %s", b.Status)
1828		}
1829		// Self-ref check
1830		for _, depID := range b.DepIDs() {
1831			if depID == b.ID && b.ID != "" {
1832				return fmt.Errorf("bead: cannot depend on self")
1833			}
1834		}
1835		return nil
