1838	// detectPrefix derives the bead ID prefix from the repository/directory name,
1839	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
1840	// workingDir is the project root to use for git commands; when empty the
1841	// process working directory is used (legacy behaviour, prone to worktree
1842	// path contamination). Falls back to DefaultPrefix if detection fails.
1843	func detectPrefix(workingDir string) string {
1844		// Try git repo root name first, running from the known project root so
1845		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
1846		// contaminate the prefix with their ephemeral directory names.
1847		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
1848		if out, err := cmd.Output(); err == nil {
1849			root := strings.TrimSpace(string(out))
1850			if root != "" {
1851				return filepath.Base(root)
1852			}
1853		}
1854		// Fall back to the provided working dir, then cwd.
1855		if workingDir != "" {
1856			return filepath.Base(workingDir)
1857		}
1858		if wd, err := os.Getwd(); err == nil {
1859			return filepath.Base(wd)
1860		}
1861		return DefaultPrefix
1862	}
