1864	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
1865		v := os.Getenv(envKey)
1866		if v == "" {
1867			return fallback
1868		}
1869		// Try as seconds (plain number)
1870		if secs, err := strconv.ParseFloat(v, 64); err == nil {
1871			return time.Duration(secs * float64(time.Second))
1872		}
1873		// Try as Go duration
1874		if d, err := time.ParseDuration(v); err == nil {
1875			return d
1876		}
1877		return fallback
1878	}
