1905	// hasCycle detects cycles in the dependency graph starting from startID.
1906	func hasCycle(deps map[string][]string, startID string) bool {
1907		visited := make(map[string]bool)
1908		stack := make(map[string]bool)
1909	
1910		var visit func(string) bool
1911		visit = func(id string) bool {
1912			visited[id] = true
1913			stack[id] = true
1914	
1915			for _, dep := range deps[id] {
1916				if !visited[dep] {
1917					if visit(dep) {
1918						return true
1919					}
1920				} else if stack[dep] {
1921					return true
1922				}
1923			}
1924	
1925			stack[id] = false
1926			return false
1927		}
1928	
1929		return visit(startID)
1930	}
