			defer wg.Done()
			rng := rand.New(rand.NewSource(int64(g * 7)))
			for i := 0; i < ops; i++ {
				// Pick two distinct beads.
				fromIdx := rng.Intn(poolSize)
				toIdx := rng.Intn(poolSize)
				if fromIdx == toIdx {
					continue
